namespace QAHub.Api.Domain.Defects;
public sealed class BugEvidence{private const int MaxBytes=10*1024*1024;private BugEvidence(){}public BugEvidence(Guid bugId,string fileName,string contentType,byte[] content,string uploadedBy){ArgumentException.ThrowIfNullOrWhiteSpace(fileName);if(content.Length is 0 or >MaxBytes)throw new ArgumentException("Evidence file must be between 1 byte and 10 MB.");Id=Guid.NewGuid();BugId=bugId;FileName=Path.GetFileName(fileName.Trim());ContentType=string.IsNullOrWhiteSpace(contentType)?"application/octet-stream":contentType.Trim();Content=content;SizeBytes=content.LongLength;UploadedBy=uploadedBy.Trim();UploadedAtUtc=DateTimeOffset.UtcNow;}public Guid Id{get;private set;}public Guid BugId{get;private set;}public string FileName{get;private set;}=string.Empty;public string ContentType{get;private set;}=string.Empty;public byte[] Content{get;private set;}=[];public long SizeBytes{get;private set;}public string UploadedBy{get;private set;}=string.Empty;public DateTimeOffset UploadedAtUtc{get;private set;}}
